VALUES
  ('cpa-moex-00918', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A有限公司，其資本額為新臺幣（下同）130萬元，有甲（出資40萬元）、乙（出資30萬元）、丙（出 資30萬元）、丁（出資20萬元）及戊（出資10萬元）共5位股東，公司章程規定設董事一人，但對股 東表決權之行使、公司解散事由等無特別規定，目前董事由甲擔任之。乙擬將其出資全部轉讓給庚，下 列敘述，何者正確？', '["乙之出資轉讓應經其他股東至少3名之同意", "乙之出資轉讓應經出資合計超過50萬元之其他股東的同意", "乙之出資轉讓應經其他全體股東之同意", "乙出資之轉讓對象限於公司其他股東，因此不得轉讓給庚"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00919', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司（下稱A公司）為上市公司，A公司對其董事違反公司法第23條規定，所得行使之歸入 權其期間最長不得超過下列何者？', '["3個月", "6個月", "1年", "2年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00920', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於公司減少資本以現金以外財產退還股款之敘述，下列何者正確？', '["退還財產之種類，由董事會以決議決定之", "退還財產抵充股款之數額，應經股東會特別決議", "退還之財產及抵充之數額，應經該收受財產股東之同意", "退還財產之價值及抵充之數額，董事會應於股東會前，報請主管機關核定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00921', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於特別股之說明，下列敘述，何者錯誤？', '["特別股若依章程規定有優先分配盈餘之權利時，尚得依章程之規定對於普通股股東分配之盈餘再參與 分配", "特別股得依章程規定有優先分配盈餘之權利，且其應分配之股息為可累積", "收回特別股之資金來源，限於發行新股或盈餘，不得以舉債方式收回特別股", "特別股對於公司剩餘財產之分派，公司章程得規定劣後於普通股"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00922', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲為A公開發行公司（下稱A公司）第2屆之董事，當選董事時之持股為100萬股。甲看好A公司未來 之前景，陸續買進股份，目前總共已持有 300 萬股。由於日圓匯率不斷走貶，致甲外匯投資失利，產生 巨額虧損。甲想出脫A公司持股套現，又想將第2屆任期做滿，甲最多可以賣出多少A公司股份？', '["50萬股", "150萬股", "250萬股", "300萬股"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00923', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 公司為非公開發行之股份有限公司，公司未來將規劃成為公開發行公司，依法須增加監察人席次，董 事長甲欲請監察人乙推薦監察人之人選。成為公開發行公司後，A公司至少應設置幾席監察人？', '["1席", "2席", "3席", "5席"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00924', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司為股份有限公司，股東B持有該公司普通股共1萬股，該公司章程規定董事席次共5席，監察人2 席，在累積投票制下，關於股東B之投票權，下列說明，何者正確？', '["B共有5萬個董事投票權，但必須分別投給5個不同之候選人", "B共有1萬個董事投票權，且得集中投給同一候選人", "B共有5萬個董事投票權，且得集中投給同一候選人", "B共有7萬個董事投票權，且得集中投給同一候選人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00925', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司（下稱A公司），向越南與印度發展業務並不順利，屋漏偏逢連夜雨，經過會計師計算 後，發現A公司竟然有高達累積虧損新臺幣1億元，且無公積可資填補，卻仍在今年分派股息紅利。債 權人甲在此情況下，依法可採取下列何種方式救濟？', '["得請求違法分得股息紅利之人退還，但不得請求賠償因此所受之損害", "得請求違法分得股息紅利之人退還，並得請求2倍懲罰性違約金", "得請求違法分得股息紅利之人退還，並得請求賠償因此所受之損害", "不得請求退還，但得請求賠償因此所受之損害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00926', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司為非公開發行公司，已發行股份總數為1000萬股，股東甲持有20萬股。今A公司擬發行新股500 萬股，其中保留10%給員工認購。以下敘述，何者錯誤？', '["股東會不得決議股東無新股認購權", "甲得依股東身分被分配認購10萬股", "給員工認購之總股數為50萬股", "萬一有未被認購之新股餘額，A公司得洽特定人認購"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00927', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司持有B公司所有股份、持有C公司有表決權股份12%、持有D公司有表決權股份31%；B公司持 有C公司有表決權股份40%、持有D公司有表決權股份10%；C公司亦持有D公司有表決權股份10%。 下列敘述，何者錯誤？', '["C公司若持有A公司股份，該股份無表決權", "D公司若持有C公司股份，該股份無表決權", "A公司若使D公司為不利益經營，致B公司因此受有利益，A公司及B公司應共同於會計年度終了時 對D公司為適當補償", "若A、B、C、D公司皆為公開發行公司，則B、C、D公司均應於每會計年度終了，造具其與A公司 間之關係報告書，而A公司則編製關係企業合併營業報告書及合併財務報表"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00928', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '經營紡織業之A股份有限公司與經營成衣製造之B股份有限公司素有業務往來，為強化彼此間之合作關 係，兩公司決定相互持有對方之有表決權股份。由於公司法對於相互投資公司設有表決權行使之限制， 為避免受到此一限制，兩家公司相互投資對方之股數，不得達有表決權股份總數之多少比例？', '["三分之一", "四分之一", "五分之一", "六分之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00929', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '證券交易法對於有價證券募集之監督，何者為正確組合？①發行人公開發行新股，須經主管機關之核准，', '["發行人公開發行新股，須向主管機關申報生效後，始得為之", "公司對於已發行之特別股 約定股息，未能按期支付者，仍得公開發行普通股", "公司資產不足抵償債務者，仍得公開發行具有優 先權之特別股", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00930', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '證券交易法上關於有價證券募集發行之管理，下列敘述，何者正確？', '["核准制的精神是公開原則；申報制則體現了實質管理原則", "我國採核准制", "我國採申報制，但仍應受公司法關於有價證券發行之規範", "我國未曾兼採核准制與申報制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00931', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司（下稱A公司）之主要債務人今遭退票，退票金額高達新臺幣數億元，A公司遂於當晚7時， 將此消息輸入公開資訊觀測站，而A公司董事長甲於隔日上午開盤時立即賣出其手中所持有A公司之股 票及普通公司債。甲之行為是否違反禁止內線交易之規定？', '["賣出股票與普通公司債皆違法", "賣出股票與普通公司債皆未違法", "賣出股票違法，賣出普通公司債未違法", "賣出股票未違法，賣出普通公司債違法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00932', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '客戶甲委託A、B及C證券商買進某上市公司股票共計1億2千多萬元，但成交後甲未履行交付義務。 下列敘述，何者錯誤？', '["甲未依約交付，受委託之A、B及C證券商仍是應履行交付義務", "甲未依約交付，C證券商亦未履行交付義務，證券交易所可指定D證券商或其他證券商代為交付", "D證券商代為交付而發生價金差額及相關費用時，應由證券交易所直接動用其賠償準備金代為支付", "D證券商代為交付而發生價金差額及相關費用，若證券交易所因此有代為支付者，則證券交易所有權向 未履行交割之C證券商追償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00933', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司持有已發行有表決權股份總數1000萬股之B上櫃公司（下稱B公司）股票350萬股，今A公司 擬再增加持有B公司之股票。以下敘述，何者錯誤？', '["若A公司擬以公開收購方式取得B公司股票，其應先向主管機關申報並公告後，始得為之", "若A公司非以現金為對價公開收購B公司股票，其無須提出具有履行支付收購對價能力之證明", "若A公司預計於同年8月1日至9月10日期間，取得B公司股票250萬股，則A公司只能以公開收 購方式取得", "一旦A公司進行B公司股票之公開收購，則其不得降低預定之公開收購數量及縮短公開收購期間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00934', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司（下稱A公司）依證券交易法令之規定，下列何者無需主動事先向投資人交付公開說明書或 對市場公開相關資訊？', '["辦理現金增資募集發行新股", "辦理可轉換公司債之募集發行", "向符合認購資格之法人私募發行特別股", "A公司擬與B公司共同對C上市公司之不特定股東以現金為對價公開收購C上市公司已發行之50%普 通股股份"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL);
